function calculateRisk(inputs) {
    let riskScore = 50; // Base risk score out of 100

    // 1. Ventilation Rate (ACH)
    if (inputs.ventilationRate < 0.3) {
        riskScore += 20; // Very Poor
    } else if (inputs.ventilationRate < 0.5) {
        riskScore += 10; // Suboptimal
    } else if (inputs.ventilationRate < 0.7) {
        riskScore -= 5;  // Adequate
    } else {
        riskScore -= 10; // Good/Excellent
    }

    // 2. Exposure Duration
    if (inputs.exposureDuration > 16) {
        riskScore += 15;
    } else if (inputs.exposureDuration >= 8) {
        riskScore += 5;
    } else {
        riskScore -= 5;
    }

    // 3. Number of Pollutant Sources
    if (inputs.numPollutantSources > 5) {
        riskScore += 20;
    } else if (inputs.numPollutantSources >= 3) {
        riskScore += 10;
    } else if (inputs.numPollutantSources >= 1) {
        riskScore += 5;
    } else {
        riskScore -= 5;
    }

    // 4. Occupant Sensitivity
    switch (inputs.occupantSensitivity) {
        case 'Low':
            riskScore -= 10;
            break;
        case 'Medium':
            riskScore += 5;
            break;
        case 'High':
            riskScore += 15;
            break;
    }

    // 5. Building Age
    if (inputs.buildingAge < 5) {
        riskScore += 10; // New construction VOCs
    } else if (inputs.buildingAge > 50) {
        riskScore += 15; // Older materials, potential mold/asbestos/lead risks
    } else if (inputs.buildingAge > 20) {
        riskScore += 5;  // Potential dust/aging HVAC
    } else {
        riskScore -= 5;  // Mid-age, often more stable
    }

    // 6. Air Purification System
    switch (inputs.airPurificationSystem) {
        case 'None':
            riskScore += 15;
            break;
        case 'Basic Filtration':
            riskScore += 5;
            break;
        case 'HEPA/Carbon':
            riskScore -= 10;
            break;
        case 'Advanced IAQ System':
            riskScore -= 15;
            break;
    }

    // 7. Humidity Level (Optimal 40-60%)
    if (inputs.humidityLevel < 30 || inputs.humidityLevel > 70) {
        riskScore += 15;
    } else if (inputs.humidityLevel < 40 || inputs.humidityLevel > 60) {
        riskScore += 5;
    } else {
        riskScore -= 10;
    }

    // 8. Known Mold Presence
    switch (inputs.knownMoldPresence) {
        case 'Yes':
            riskScore += 25;
            break;
        case 'Unsure':
            riskScore += 10;
            break;
        case 'No':
            riskScore -= 5;
            break;
    }

    // 9. Pest Presence
    if (inputs.pestPresence === 'Yes') {
        riskScore += 10; // Allergenic droppings, dander, potential for disease vectors
    }

    // Ensure score is within 0-100 bounds
    riskScore = Math.max(0, Math.min(100, riskScore));

    let riskCategory;
    let recommendations = [];

    if (riskScore <= 25) {
        riskCategory = 'Low Risk';
        recommendations.push('Your indoor air quality appears good. Continue with routine maintenance and monitoring. Consider occasional professional IAQ checks.');
    } else if (riskScore <= 50) {
        riskCategory = 'Moderate Risk';
        recommendations.push('Your indoor air quality has moderate risks. Focus on improving ventilation, reducing pollutant sources, and maintaining optimal humidity. Consider upgrading air filtration.');
    } else if (riskScore <= 75) {
        riskCategory = 'High Risk';
        recommendations.push('Your indoor air quality presents significant health risks. Immediate action is recommended. Improve ventilation, identify and eliminate pollutant sources, address mold concerns, and invest in high-efficiency air purification. Professional IAQ assessment is highly advised.');
    } else {
        riskCategory = 'Severe Risk';
        recommendations.push('Your indoor air quality poses severe health risks, potentially requiring urgent intervention. Seek a professional indoor air quality assessment immediately. Address all identified sources, ensure robust ventilation, remediate mold, and consider temporary relocation if symptoms are severe.');
    }

    // Add general recommendations based on key factors
    if (inputs.ventilationRate < 0.5) {
        recommendations.push('ACTION: Increase ventilation by opening windows, using exhaust fans, or considering a balanced ventilation system (e.g., HRV/ERV).');
    }
    if (inputs.numPollutantSources > 2) {
        recommendations.push('ACTION: Identify and reduce pollutant sources. Opt for low-VOC products, avoid indoor smoking, use natural cleaning agents, and ventilate during cooking.');
    }
    if (inputs.humidityLevel < 40 || inputs.humidityLevel > 60) {
        recommendations.push('ACTION: Maintain indoor humidity between 40-60% using humidifiers/dehumidifiers. This inhibits mold growth and reduces respiratory irritation.');
    }
    if (inputs.knownMoldPresence === 'Yes' || inputs.knownMoldPresence === 'Unsure') {
        recommendations.push('ACTION: Investigate and remediate any known or suspected mold issues promptly and professionally. Control moisture sources.');
    }
    if (inputs.airPurificationSystem === 'None' || inputs.airPurificationSystem === 'Basic Filtration') {
        recommendations.push('ACTION: Consider upgrading your air filtration to MERV 8+ or investing in a standalone HEPA air purifier.');
    }
     if (inputs.pestPresence === 'Yes') {
        recommendations.push('ACTION: Address pest infestations immediately and prevent future occurrences, as pest allergens can significantly impact IAQ.');
    }

    return {
        healthRiskScore: riskScore,
        riskCategory: riskCategory,
        recommendations: recommendations.join(' ')
    };
}
